import { z } from "zod";

const registrationSchema = z
  .object({
    username: z
      .string()
      .min(3, "Username must be at least 3 characters long"),
    email: z
      .string()
      .min(1, "Email is required")
      .email("Invalid email address"),
    role: z.enum(["user", "admin", "contributor"]),
    otherInfo: z.string().optional(),
    newsletter: z.boolean().default(false),
    frequency: z.enum(["daily", "weekly", "monthly"]).optional(),
    bio: z.string().optional(),
  })
  .superRefine((data, refineContext) => {
    // otherInfo required when role === "contributor"
    if (data.role === "contributor" && !data.otherInfo) {
      refineContext.addIssue({
        path: ["otherInfo"],
        code: "custom",
        message: "Other information is required for contributors",
      });
    }

    // frequency required when newsletter is true
    if (data.newsletter === true && !data.frequency) {
      refineContext.addIssue({
        path: ["frequency"],
        code: "custom",
        message: "Newsletter frequency is required when subscribed",
      });
    }
  });

export type RegistrationFormValues = z.infer<typeof registrationSchema>;
export { registrationSchema };

