import { z } from 'zod';

const REGISTRATION_SCHEMA = z.object({
  username: z.string().min(3, 'Username must be at least 3 characters'),
  email: z.string().email('Valid email is required'),
  role: z.enum(['user', 'admin', 'contributor']),
  otherInfo: z.string().optional(),
  newsletter: z.boolean().optional(),
  frequency: z.enum(['daily', 'weekly', 'monthly']).optional(),
  bio: z.string().optional(),
}).superRefine((data, ctx) => {
  // otherInfo required when role === "contributor"
  if (data.role === 'contributor' && (!data.otherInfo || data.otherInfo.trim() === '')) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      path: ['otherInfo'],
      message: 'Other information is required for contributors',
    });
  }

  // frequency required when newsletter === true
  if (data.newsletter === true && (!data.frequency || data.frequency === '')) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      path: ['frequency'],
      message: 'Frequency is required when newsletter subscription is enabled',
    });
  }
});

export type RegistrationFormValues = z.infer<typeof REGISTRATION_SCHEMA>;
export { REGISTRATION_SCHEMA };

